const body = $input.first().json;

// Extrai dados da mensagem recebida pelo WhatsApp Business API
const entry = body.entry?.[0];
const change = entry?.changes?.[0];
const value = change?.value;

// Ignora notificações que não são mensagens de texto
const message = value?.messages?.[0];
if (!message || message.type !== 'text') {
  return [{ json: { skip: true } }];
}

// Ignora mensagens enviadas pelo próprio bot
const fromMe = message.from === value?.metadata?.phone_number_id;
if (fromMe) {
  return [{ json: { skip: true } }];
}

const phone = message.from;
const messageText = message.text?.body?.trim() || '';
const name = value?.contacts?.[0]?.profile?.name || 'usuário';
const messageId = message.id;
const phoneNumberId = value?.metadata?.phone_number_id;

if (!messageText) {
  return [{ json: { skip: true } }];
}

return [{
  json: {
    phone,
    name,
    message: messageText,
    messageId,
    phoneNumberId,
    skip: false
  }
}];

const tutoriais = $input.first().json;

// Formata tutoriais em texto compacto para o contexto do LLM
const lista = tutoriais.map(t =>
  `[${t.id}] ${t.titulo}\nDescrição: ${t.descricao}\nPassos: ${t.passos.join(' > ')}`
).join('\n\n');

return [{ json: { tutoriaisTexto: lista } }];

const mensagemUsuario = $('Extrai dados da mensagem').first().json.message;
const nomeUsuario = $('Extrai dados da mensagem').first().json.name;
const tutoriaisTexto = $('Formata tutoriais para contexto').first().json.tutoriaisTexto;

const systemPrompt = `Você é o ADSI, um assistente digital criado para ajudar idosos e pessoas com pouca experiência em tecnologia a usarem notebooks e celulares com mais segurança e confiança.

REGRAS DE COMPORTAMENTO:
- Use linguagem simples, calorosa e paciente — como se fosse um familiar explicando
- Nunca use termos técnicos sem explicar o que significam
- Resposta máxima: 5 linhas curtas (o usuário lê no celular)
- Se identificar o problema do usuário nos tutoriais abaixo, explique os 2 ou 3 passos mais importantes
- Se não souber responder, diga gentilmente que a pessoa pode pedir ajuda a um familiar ou técnico
- Sempre termine com uma frase encorajadora
- Use emojis com moderação para tornar a conversa mais amigável
- Nunca mencione que é uma IA, a menos que seja diretamente perguntado

TUTORIAIS DISPONÍVEIS NO ADSI:
${tutoriaisTexto}`;

return [{
  json: {
    systemPrompt,
    userMessage: `${nomeUsuario} diz: ${mensagemUsuario}`,
    nomeUsuario,
    mensagemOriginal: mensagemUsuario
  }
}];

const groqResponse = $input.first().json;
const resposta = groqResponse.choices?.[0]?.message?.content ||
  'Olá! Não consegui entender bem. Pode explicar com outras palavras? 😊';

return [{
  json: {
    phone: $('Extrai dados da mensagem').first().json.phone,
    phoneNumberId: $('Extrai dados da mensagem').first().json.phoneNumberId,
    name: $('Extrai dados da mensagem').first().json.name,
    resposta: resposta.trim(),
    perguntaOriginal: $('Extrai dados da mensagem').first().json.message
  }
}];
